export const ICON_CATEGORIES = Array.from(new Set(ICONS.map(i => i.category)))

export function searchIcons(query: string, category?: string): IconEntry[] {
  let results = ICONS
  if (category && category !== 'All') {
    results = results.filter(i => i.category === category)
  }
  if (query.trim()) {
    const q = query.toLowerCase()
    results = results.filter(i =>
      i.name.includes(q) || i.label.toLowerCase().includes(q) || i.category.toLowerCase().includes(q)
    )
  }
  return results
}

export function getIconByName(name: string): IconEntry | undefined {
  return ICONS.find(i => i.name === name)
}

/** Resolve a stored icon value to an array of SVG path `d` strings.
 *  Handles both new `"lucide:waves"` format and legacy raw SVG path strings. */
export function resolveIconPaths(value: string): string[] {
  if (!value) return []
  if (value.startsWith('lucide:')) {
    const name = value.slice('lucide:'.length)
    return getIconByName(name)?.paths ?? []
  }
  // Legacy: raw SVG path string
  return [value]
}
